// Dead Letter Queue - Capture failed syncs for manual processing
const leadData = $('Calculate Lead Score').first().json;
const error = $input.first().json;

return {
  json: {
    status: 'SYNC_FAILED',
    leadData: {
      name: leadData.name,
      phone: leadData.phone,
      email: leadData.email,
      address: leadData.address,
      notes: leadData.notes,
      source: leadData.source,
      score: leadData.scoring?.score,
      tier: leadData.scoring?.tier,
      isEmergency: leadData.scoring?.isEmergency,
      ghlContactId: leadData.sourceDetails?.ghlContactId
    },
    error: {
      message: error.message || error.error || 'Unknown API error',
      statusCode: error.statusCode || error.code || null,
      body: error.body || null
    },
    metadata: {
      failedAt: new Date().toISOString(),
      vapiCallInitiated: true,
      requiresManualEntry: true
    }
  }
};

